/* ============================================================
   reports.css — สไตล์เฉพาะหน้ารายงาน
   (dashboard-report, activity-report, student-report, score-hours-report)
   ============================================================ */

/* ---------- แถบ export (PDF/Excel/CSV) ---------- */
.export-bar {
  display: flex;
  gap: var(--space-2);
}

.export-btn {
  display: inline-flex;
  align-items: center;
  gap: 6px;
}

.export-btn.pdf i { color: var(--color-status-cancelled); }
.export-btn.excel i { color: var(--color-status-active); }
.export-btn.csv i { color: var(--color-status-completed); }

/* ---------- Filter bar ของหน้ารายงาน ---------- */
.report-filter-bar {
  background: var(--color-bg);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  padding: var(--space-4);
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-3);
  align-items: flex-end;
  margin-bottom: var(--space-5);
}

.report-filter-field {
  display: flex;
  flex-direction: column;
  gap: 6px;
  min-width: 160px;
}

.report-filter-field label {
  font-size: var(--fs-tiny);
  color: var(--color-text-muted);
  font-weight: 500;
}

.report-filter-field select,
.report-filter-field input {
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  padding: 9px 12px;
  font-size: var(--fs-small);
}

/* ---------- Chart card grid เฉพาะหน้า dashboard-report ---------- */
.report-chart-card {
  background: var(--color-bg);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  padding: var(--space-5);
}

.report-chart-title {
  font-size: var(--fs-h3);
  font-weight: 600;
  margin-bottom: var(--space-4);
}

.report-chart-legend {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-3);
  margin-top: var(--space-3);
  font-size: var(--fs-tiny);
  color: var(--color-text-muted);
}

.report-chart-legend span {
  display: flex;
  align-items: center;
  gap: 6px;
}

.report-chart-legend .dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
}

/* ---------- รายการกิจกรรมล่าสุด (recent activities feed) ---------- */
.recent-activity-item {
  display: flex;
  align-items: center;
  gap: var(--space-3);
  padding: var(--space-3) 0;
  border-bottom: 1px solid var(--color-border);
}
.recent-activity-item:last-child { border-bottom: none; }

.recent-activity-icon {
  width: 40px;
  height: 40px;
  border-radius: var(--radius-md);
  background: var(--color-primary-light);
  color: var(--color-primary);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 18px;
  flex-shrink: 0;
}

.recent-activity-title {
  font-size: var(--fs-small);
  font-weight: 500;
}

.recent-activity-time {
  font-size: var(--fs-tiny);
  color: var(--color-text-faint);
}

/* ---------- Print-friendly (ตอน export/print รายงาน) ---------- */
@media print {
  .sidebar, .topbar, .report-filter-bar, .export-bar, .page-header-actions {
    display: none !important;
  }
  .app-main { margin-left: 0 !important; }
}

@media (max-width: 768px) {
  .report-filter-bar { flex-direction: column; align-items: stretch; }
  .report-filter-field { min-width: 0; }
}
